{
  "name": "AgriSage MVP",
  "description": "A comprehensive multilingual agricultural platform providing crop guidance, market rates, waste management, and AI-powered farming assistance with specialized accessibility features.",
  "requestFramePermissions": [
    "microphone",
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Language = 'en' | 'hi' | 'ta' | 'pa' | 'mr';

export interface Translation {
  title: string;
  tagline: string;
  cropSuggestion: string;
  marketplace: string;
  marketPrices: string;
  climateAlerts: string;
  stubbleManagement: string;
  carbonCredits: string;
  plantingDetails: string;
  askAi: string;
}

export interface CropSuggestion {
  crop: string;
  variety: string;
  waterLevel: string;
  soilSuitability: string;
  expectedYield: string;
}

export interface MarketRate {
  commodity: string;
  price: number;
  unit: string;
  trend: 'up' | 'down' | 'stable';
  history: { date: string; price: number }[];
}

export enum AccessibilityMode {
  NORMAL = 'NORMAL',
  HIGH_CONTRAST = 'HIGH_CONTRAST',
  ICON_ONLY = 'ICON_ONLY'
}

export interface AppState {
  language: Language;
  accessibility: AccessibilityMode;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getFarmingExpertResponse = async (query: string, language: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `User language: ${language}. Role: Senior Agricultural Scientist. Answer this query: ${query}`,
      config: {
        systemInstruction: "You are AgriSage, a helpful agricultural expert assisting farmers with crops, pests, market trends, and modern farming techniques. Be concise and practical.",
        temperature: 0.7,
      }
    });
    return response.text || "I'm sorry, I couldn't process that right now.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "The expert is currently offline. Please try again in a moment.";
  }
};

export const getCropSuggestions = async (soilType: string, location: string, month: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Suggest 3 crops for soil: ${soilType}, location: ${location}, month: ${month}. Return as JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              crop: { type: Type.STRING },
              variety: { type: Type.STRING },
              waterLevel: { type: Type.STRING },
              expectedYield: { type: Type.STRING }
            },
            required: ["crop", "variety", "waterLevel", "expectedYield"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Suggestion Error:", error);
    return [];
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, Send, X, Bot, User } from 'lucide-react';
import { getFarmingExpertResponse } from '../services/geminiService';
import { Language } from '../types';

interface Message {
  role: 'user' | 'assistant';
  text: string;
}

interface VoiceChatProps {
  language: Language;
  onClose: () => void;
}

const VoiceChat: React.FC<VoiceChatProps> = ({ language, onClose }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', text: "Hello! I am your AgriSage assistant. How can I help you today?" }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (text: string) => {
    if (!text.trim()) return;

    const userMsg: Message = { role: 'user', text };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    const aiResponse = await getFarmingExpertResponse(text, language);
    setMessages(prev => [...prev, { role: 'assistant', text: aiResponse }]);
    setIsProcessing(false);

    // Text to Speech
    const utterance = new SpeechSynthesisUtterance(aiResponse);
    utterance.lang = language === 'en' ? 'en-US' : (language === 'hi' ? 'hi-IN' : 'en-US');
    window.speechSynthesis.speak(utterance);
  };

  const toggleListening = () => {
    if (isListening) {
      setIsListening(false);
      return;
    }

    const SpeechRecognition = (window as any).webkitSpeechRecognition || (window as any).SpeechRecognition;
    if (!SpeechRecognition) {
      alert("Voice recognition not supported in this browser.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = language === 'en' ? 'en-US' : (language === 'hi' ? 'hi-IN' : 'en-US');
    recognition.onstart = () => setIsListening(true);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      handleSend(transcript);
    };
    recognition.onend = () => setIsListening(false);
    recognition.start();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl flex flex-col h-[80vh] overflow-hidden">
        {/* Header */}
        <div className="bg-green-600 p-4 text-white flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Bot className="w-6 h-6" />
            <h3 className="font-bold text-lg">AgriSage AI Expert</h3>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-green-700 rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Chat Body */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] p-3 rounded-2xl shadow-sm ${
                msg.role === 'user' 
                ? 'bg-green-600 text-white rounded-tr-none' 
                : 'bg-white text-gray-800 rounded-tl-none border border-gray-100'
              }`}>
                <p className="text-sm leading-relaxed">{msg.text}</p>
              </div>
            </div>
          ))}
          {isProcessing && (
            <div className="flex justify-start">
              <div className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100 flex gap-1">
                <span className="w-2 h-2 bg-gray-300 rounded-full animate-bounce"></span>
                <span className="w-2 h-2 bg-gray-300 rounded-full animate-bounce delay-100"></span>
                <span className="w-2 h-2 bg-gray-300 rounded-full animate-bounce delay-200"></span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Footer */}
        <div className="p-4 border-t bg-white space-y-3">
          <div className="flex gap-2">
            <button 
              onClick={toggleListening}
              className={`p-3 rounded-full transition-all ${
                isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              {isListening ? <MicOff className="w-6 h-6" /> : <Mic className="w-6 h-6" />}
            </button>
            <input 
              type="text" 
              placeholder="Type your question..." 
              className="flex-1 border border-gray-200 rounded-full px-4 py-2 focus:outline-none focus:ring-2 focus:ring-green-500"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend(inputValue)}
            />
            <button 
              onClick={() => handleSend(inputValue)}
              className="p-3 bg-green-600 text-white rounded-full hover:bg-green-700 transition-colors"
            >
              <Send className="w-5 h-5" />
            </button>
          </div>
          <p className="text-[10px] text-center text-gray-400">
            Powered by AgriSage Gemini AI. Expert guidance for sustainable farming.
          </p>
        </div>
      </div>
    </div>
  );
};

export default VoiceChat;

import React, { useState } from 'react';
import { Sprout, MapPin, Search, Loader2 } from 'lucide-react';
import { getCropSuggestions } from '../services/geminiService';
import { Language } from '../types';

const CropAdvisor: React.FC<{ language: Language }> = ({ language }) => {
  const [soilType, setSoilType] = useState('Alluvial');
  const [location, setLocation] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<any[]>([]);

  const handleRecommend = async () => {
    setLoading(true);
    const month = new Date().toLocaleString('en-US', { month: 'long' });
    const suggestions = await getCropSuggestions(soilType, location || 'Punjab, India', month);
    setResults(suggestions);
    setLoading(false);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border p-6 space-y-6">
      <div className="flex items-center gap-3">
        <div className="p-2 bg-green-100 rounded-lg text-green-600">
          <Sprout className="w-6 h-6" />
        </div>
        <h2 className="text-xl font-bold text-gray-800">Crop Recommendations</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700">Soil Type</label>
          <select 
            className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-green-500"
            value={soilType}
            onChange={(e) => setSoilType(e.target.value)}
          >
            <option>Alluvial</option>
            <option>Black Soil</option>
            <option>Red Soil</option>
            <option>Laterite</option>
            <option>Desert</option>
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700">Location</label>
          <div className="relative">
            <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input 
              type="text" 
              placeholder="e.g. Haryana" 
              className="w-full border rounded-lg pl-10 pr-4 py-2.5 focus:ring-2 focus:ring-green-500"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
            />
          </div>
        </div>
      </div>

      <button 
        onClick={handleRecommend}
        disabled={loading}
        className="w-full bg-green-600 hover:bg-green-700 text-white font-semibold py-3 rounded-lg flex items-center justify-center gap-2 transition-colors disabled:opacity-50"
      >
        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Search className="w-5 h-5" />}
        Get Best Crops for Today
      </button>

      {results.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-fade-in">
          {results.map((res, i) => (
            <div key={i} className="border rounded-xl p-4 bg-green-50/30 border-green-100 flex flex-col justify-between">
              <div>
                <h4 className="font-bold text-green-800 text-lg">{res.crop}</h4>
                <p className="text-xs text-gray-500 mb-2">{res.variety}</p>
                <div className="space-y-2">
                  <div className="flex justify-between text-xs">
                    <span className="text-gray-500">Water Req:</span>
                    <span className="font-medium">{res.waterLevel}</span>
                  </div>
                  <div className="flex justify-between text-xs">
                    <span className="text-gray-500">Est. Yield:</span>
                    <span className="font-medium">{res.expectedYield}</span>
                  </div>
                </div>
              </div>
              <button className="mt-4 text-xs font-bold text-green-600 hover:underline">View Planting Guide →</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default CropAdvisor;

