export default MarketDashboard;

import React, { useState, useEffect } from 'react';
import { 
  Menu, 
  Settings, 
  Bell, 
  Search, 
  Globe, 
  User, 
  Zap, 
  Eye, 
  Accessibility 
} from 'lucide-react';
import { Language, AccessibilityMode } from './types';
import { UI_TRANSLATIONS, LANGUAGES, FEATURE_CARDS } from './constants';
import VoiceChat from './components/VoiceChat';
import CropAdvisor from './components/CropAdvisor';
import MarketDashboard from './components/MarketDashboard';
import SustainablePortal from './components/SustainablePortal';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [accessMode, setAccessMode] = useState<AccessibilityMode>(AccessibilityMode.NORMAL);
  const [activeTab, setActiveTab] = useState('home');
  const [showAi, setShowAi] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const t = UI_TRANSLATIONS[lang];

  // Apply high contrast class to body
  useEffect(() => {
    if (accessMode === AccessibilityMode.HIGH_CONTRAST) {
      document.body.classList.add('high-contrast');
    } else {
      document.body.classList.remove('high-contrast');
    }
  }, [accessMode]);

  const toggleAccess = () => {
    if (accessMode === AccessibilityMode.NORMAL) setAccessMode(AccessibilityMode.HIGH_CONTRAST);
    else if (accessMode === AccessibilityMode.HIGH_CONTRAST) setAccessMode(AccessibilityMode.ICON_ONLY);
    else setAccessMode(AccessibilityMode.NORMAL);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'crop': return <CropAdvisor language={lang} />;
      case 'rates': return <MarketDashboard />;
      case 'waste': return <SustainablePortal />;
      default: return (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {FEATURE_CARDS.map((card) => (
            <button
              key={card.id}
              onClick={() => card.id === 'ai' ? setShowAi(true) : setActiveTab(card.id)}
              className={`p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-4 transition-all hover:scale-105 active:scale-95 ${card.color} ${accessMode === AccessibilityMode.ICON_ONLY ? 'aspect-square' : ''}`}
            >
              <div className="p-3 bg-white/50 rounded-full">
                {React.cloneElement(card.icon as React.ReactElement, { size: 32 })}
              </div>
              {accessMode !== AccessibilityMode.ICON_ONLY && (
                <span className="font-bold text-center text-sm md:text-base">
                  {(t as any)[card.titleKey]}
                </span>
              )}
            </button>
          ))}
        </div>
      );
    }
  };

  return (
    <div className={`min-h-screen flex flex-col ${accessMode === AccessibilityMode.HIGH_CONTRAST ? 'bg-black text-white' : 'bg-gray-50'}`}>
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-2 lg:hidden">
              <Menu />
            </button>
            <div 
              className="flex items-center gap-2 cursor-pointer" 
              onClick={() => setActiveTab('home')}
            >
              <div className="bg-green-600 p-2 rounded-lg text-white">
                <Zap className="fill-current" />
              </div>
              <h1 className="text-2xl font-black text-green-600 hidden md:block">AgriSage</h1>
            </div>
          </div>

          <div className="flex-1 max-w-md mx-6 hidden md:block">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
              <input 
                type="text" 
                placeholder="Search crops, fertilizers..." 
                className="w-full bg-gray-100 rounded-full pl-10 pr-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-green-500"
              />
            </div>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            {/* Language Picker */}
            <div className="relative group">
              <button className="flex items-center gap-1 p-2 bg-gray-100 rounded-lg hover:bg-gray-200 transition">
                <Globe className="w-5 h-5 text-gray-600" />
                <span className="text-sm font-medium uppercase">{lang}</span>
              </button>
              <div className="absolute right-0 mt-2 w-32 bg-white border rounded-xl shadow-xl hidden group-hover:block overflow-hidden animate-fade-in">
                {LANGUAGES.map(l => (
                  <button 
                    key={l.code} 
                    onClick={() => setLang(l.code)}
                    className={`w-full text-left px-4 py-2 text-sm hover:bg-green-50 transition ${lang === l.code ? 'text-green-600 font-bold' : ''}`}
                  >
                    {l.name}
                  </button>
                ))}
              </div>
            </div>

            {/* Accessibility Toggle */}
            <button 
              onClick={toggleAccess}
              title="Change accessibility mode"
              className={`p-2 rounded-lg transition ${accessMode !== AccessibilityMode.NORMAL ? 'bg-amber-100 text-amber-600' : 'bg-gray-100 text-gray-600'}`}
            >
              <Accessibility className="w-5 h-5" />
            </button>

            <button className="p-2 bg-gray-100 rounded-lg text-gray-600 relative">
              <Bell className="w-5 h-5" />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
            </button>

            <button className="w-10 h-10 bg-green-100 text-green-600 rounded-full flex items-center justify-center border-2 border-white shadow-sm">
              <User className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8">
        {/* Sub Header / Welcome */}
        <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-3xl font-black text-gray-800">{t.title} Dashboard</h2>
            <p className="text-gray-500 font-medium">{t.tagline}</p>
          </div>
          <div className="flex gap-3">
            <div className="bg-white p-4 rounded-xl shadow-sm border flex items-center gap-4">
              <div className="bg-blue-100 p-2 rounded-full text-blue-600">
                <Globe className="w-5 h-5" />
              </div>
              <div>
                <p className="text-xs text-gray-400">Weather</p>
                <p className="font-bold text-gray-800">28°C Sunny</p>
              </div>
            </div>
            {activeTab !== 'home' && (
              <button 
                onClick={() => setActiveTab('home')}
                className="bg-gray-800 text-white px-6 rounded-xl font-bold hover:bg-gray-900 transition flex items-center gap-2"
              >
                Back Home
              </button>
            )}
          </div>
        </div>

        {/* Dynamic Content */}
        <div className="space-y-8 pb-20">
          {renderContent()}
        </div>
      </main>

      {/* Floating Action Button for AI */}
      <button 
        onClick={() => setShowAi(true)}
        className="fixed bottom-6 right-6 p-4 bg-green-600 text-white rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-transform z-40 flex items-center gap-2"
      >
        <Zap className="w-6 h-6 fill-white" />
        <span className="font-bold hidden md:block">{t.askAi}</span>
      </button>

      {/* Overlays */}
      {showAi && (
        <VoiceChat 
          language={lang} 
          onClose={() => setShowAi(false)} 
        />
      )}

      {/* Footer Nav (Mobile) */}
