import React, { useState } from 'react';
import { BookOpen, Search, Loader2, Leaf, Droplets, Info } from 'lucide-react';
import { getPlantingGuide } from '../services/geminiService';
import { Language } from '../types';

const PlantingGuide: React.FC<{ language: Language }> = ({ language }) => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [guide, setGuide] = useState<string | null>(null);

  const handleSearch = async () => {
    if (!query.trim()) return;
    setLoading(true);
    const result = await getPlantingGuide(query, language);
    setGuide(result || "Guide not available.");
    setLoading(false);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-orange-100 rounded-lg text-orange-600">
            <BookOpen className="w-6 h-6" />
          </div>
          <h2 className="text-xl font-bold text-gray-800">Crop-Specific Sowing Guide</h2>
        </div>

        <div className="relative mb-8">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          <input 
            type="text" 
            placeholder="Search for a crop (e.g. Wheat, Basmati Rice, Cotton)..." 
            className="w-full pl-12 pr-32 py-4 bg-gray-50 border rounded-2xl text-lg focus:ring-2 focus:ring-orange-500 transition-all outline-none"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
          />
          <button 
            onClick={handleSearch}
            disabled={loading}
            className="absolute right-2 top-1/2 -translate-y-1/2 px-6 py-2 bg-orange-600 text-white font-bold rounded-xl hover:bg-orange-700 transition disabled:opacity-50"
          >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Get Guide'}
          </button>
        </div>

        {!guide && !loading && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {['Wheat', 'Cotton', 'Mustard'].map((crop) => (
              <button 
                key={crop}
                onClick={() => { setQuery(crop); }}
                className="p-4 border border-dashed rounded-xl text-left hover:bg-orange-50 hover:border-orange-200 transition-colors group"
              >
                <div className="flex justify-between items-center">
                  <span className="font-bold text-gray-700">{crop}</span>
                  <Leaf className="w-4 h-4 text-orange-300 group-hover:text-orange-500" />
                </div>
                <p className="text-[10px] text-gray-400 mt-1">Commonly searched guide</p>
              </button>
            ))}
          </div>
        )}

        {guide && (
          <div className="mt-8 animate-fade-in">
            <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100 relative">
               <div className="absolute top-4 right-4 text-orange-200"><Info className="w-12 h-12" /></div>
               <h3 className="text-2xl font-black text-gray-900 mb-4">{query} Planting Details</h3>
               <div className="prose prose-sm max-w-none text-gray-700 leading-relaxed">
                  <div dangerouslySetInnerHTML={{ __html: guide.replace(/\n/g, '<br/>') }} />
               </div>
               <div className="mt-8 grid grid-cols-2 gap-4">
                 <div className="flex items-center gap-2 p-3 bg-blue-50 text-blue-700 rounded-xl">
                   <Droplets className="w-4 h-4" />
                   <span className="text-xs font-bold uppercase">Optimal Watering Frequency</span>
                 </div>
                 <div className="flex items-center gap-2 p-3 bg-green-50 text-green-700 rounded-xl">
                   <Leaf className="w-4 h-4" />
                   <span className="text-xs font-bold uppercase">Organic Fertilizer Ready</span>
                 </div>
               </div>
            </div>
            <button 
              onClick={() => window.print()} 
              className="mt-4 text-sm font-bold text-gray-500 hover:text-gray-800 flex items-center gap-1 mx-auto"
            >
              Save as PDF Guide
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

