import React, { useState, useEffect } from 'react';
import { 
  Menu, 
  Settings, 
  Bell, 
  Search, 
  Globe, 
  User, 
  Zap, 
  Accessibility,
  Sprout,
  CloudSun,
  LogOut,
  MapPin,
  ChevronDown
} from 'lucide-react';
import { Language, AccessibilityMode, User as UserType } from './types';
import { UI_TRANSLATIONS, LANGUAGES, FEATURE_CARDS, LOCATIONS } from './constants';
import { dbService } from './services/dbService';
import VoiceChat from './components/VoiceChat';
import CropAdvisor from './components/CropAdvisor';
import MarketDashboard from './components/MarketDashboard';
import SustainablePortal from './components/SustainablePortal';
import Marketplace from './components/Marketplace';
import ClimateAlerts from './components/ClimateAlerts';
import PlantingGuide from './components/PlantingGuide';
import Auth from './components/Auth';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [accessMode, setAccessMode] = useState<AccessibilityMode>(AccessibilityMode.NORMAL);
  const [activeTab, setActiveTab] = useState('home');
  const [showAi, setShowAi] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserType | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true);
  const [activeLocation, setActiveLocation] = useState<string>('');

  const t = UI_TRANSLATIONS[lang];

  // Auth and Session check
  useEffect(() => {
    const user = dbService.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      setActiveLocation(user.location);
    }
    setIsAuthChecking(false);
  }, []);

  // Apply high contrast class to body
  useEffect(() => {
    if (accessMode === AccessibilityMode.HIGH_CONTRAST) {
      document.body.classList.add('high-contrast');
    } else {
      document.body.classList.remove('high-contrast');
    }
  }, [accessMode]);

  const toggleAccess = () => {
    if (accessMode === AccessibilityMode.NORMAL) setAccessMode(AccessibilityMode.HIGH_CONTRAST);
    else if (accessMode === AccessibilityMode.HIGH_CONTRAST) setAccessMode(AccessibilityMode.ICON_ONLY);
    else setAccessMode(AccessibilityMode.NORMAL);
  };

  const handleLogout = () => {
    dbService.logout();
    setCurrentUser(null);
    setActiveTab('home');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'crop': return <CropAdvisor language={lang} initialLocation={activeLocation} />;
      case 'rates': return <MarketDashboard />;
      case 'waste': 
      case 'carbon': return <SustainablePortal />;
      case 'market': return <Marketplace />;
      case 'climate': return <ClimateAlerts location={activeLocation} />;
      case 'guide': return <PlantingGuide language={lang} />;
      default: return (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {FEATURE_CARDS.map((card) => (
            <button
              key={card.id}
              onClick={() => card.id === 'ai' ? setShowAi(true) : setActiveTab(card.id)}
              className={`p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-4 transition-all hover:scale-105 active:scale-95 ${card.color} ${accessMode === AccessibilityMode.ICON_ONLY ? 'aspect-square' : ''}`}
            >
              <div className="p-3 bg-white/50 rounded-full">
                {/* Fixed TypeScript error by adding generic type for cloneElement to handle 'size' prop */}
                {React.cloneElement(card.icon as React.ReactElement<{ size?: number }>, { size: 32 })}
              </div>
              {accessMode !== AccessibilityMode.ICON_ONLY && (
                <span className="font-bold text-center text-sm md:text-base">
                  {(t as any)[card.titleKey]}
                </span>
              )}
            </button>
          ))}
        </div>
      );
    }
  };

  if (isAuthChecking) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-green-50">
        <Sprout className="w-12 h-12 text-green-600 animate-bounce" />
      </div>
    );
  }

  if (!currentUser) {
    return <Auth onLoginSuccess={(user) => {
      setCurrentUser(user);
      setActiveLocation(user.location);
    }} />;
  }

  return (
    <div className={`min-h-screen flex flex-col ${accessMode === AccessibilityMode.HIGH_CONTRAST ? 'bg-black text-white' : 'bg-gray-50'}`}>
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-2 lg:hidden">
              <Menu />
            </button>
            <div 
              className="flex items-center gap-2 cursor-pointer" 
              onClick={() => setActiveTab('home')}
            >
              <div className="bg-green-600 p-2 rounded-lg text-white">
                <Zap className="fill-current" />
              </div>
              <h1 className="text-2xl font-black text-green-600 hidden md:block">AgriSage</h1>
            </div>
          </div>

          <div className="flex-1 max-w-md mx-6 hidden lg:block">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
              <input 
                type="text" 
                placeholder="Search crops, fertilizers..." 
                className="w-full bg-gray-100 rounded-full pl-10 pr-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-green-500"
              />
            </div>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            {/* Global Location Picker */}
            <div className="relative group hidden sm:block">
              <button className="flex items-center gap-2 p-2 bg-green-50 border border-green-100 rounded-lg hover:bg-green-100 transition text-green-700">
                <MapPin className="w-4 h-4" />
                <span className="text-xs font-bold max-w-[100px] truncate">{activeLocation}</span>
                <ChevronDown className="w-3 h-3 opacity-50" />
              </button>
              <div className="absolute right-0 mt-2 w-56 bg-white border rounded-xl shadow-xl hidden group-hover:block overflow-hidden animate-fade-in z-50">
                <div className="p-3 border-b bg-gray-50">
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">Switch Location</p>
                </div>
                <div className="max-h-64 overflow-y-auto">
                  {LOCATIONS.map(loc => (
                    <button 
                      key={loc} 
                      onClick={() => setActiveLocation(loc)}
                      className={`w-full text-left px-4 py-3 text-xs hover:bg-green-50 transition flex items-center gap-2 ${activeLocation === loc ? 'text-green-600 font-bold bg-green-50/50' : 'text-gray-600'}`}
                    >
                      <MapPin className={`w-3 h-3 ${activeLocation === loc ? 'text-green-600' : 'text-gray-300'}`} />
                      {loc}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Language Picker */}
            <div className="relative group">
              <button className="flex items-center gap-1 p-2 bg-gray-100 rounded-lg hover:bg-gray-200 transition">
                <Globe className="w-5 h-5 text-gray-600" />
                <span className="text-sm font-medium uppercase">{lang}</span>
              </button>
              <div className="absolute right-0 mt-2 w-32 bg-white border rounded-xl shadow-xl hidden group-hover:block overflow-hidden animate-fade-in z-50">
                {LANGUAGES.map(l => (
                  <button 
                    key={l.code} 
                    onClick={() => setLang(l.code)}
                    className={`w-full text-left px-4 py-2 text-sm hover:bg-green-50 transition ${lang === l.code ? 'text-green-600 font-bold' : ''}`}
                  >
                    {l.name}
                  </button>
                ))}
              </div>
            </div>

            {/* Accessibility Toggle */}
            <button 
              onClick={toggleAccess}
              title="Change accessibility mode"
              className={`p-2 rounded-lg transition ${accessMode !== AccessibilityMode.NORMAL ? 'bg-amber-100 text-amber-600' : 'bg-gray-100 text-gray-600'}`}
            >
              <Accessibility className="w-5 h-5" />
            </button>

            <button className="p-2 bg-gray-100 rounded-lg text-gray-600 relative">
              <Bell className="w-5 h-5" />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
            </button>

            {/* User Profile Menu */}
            <div className="relative group">
              <button className="w-10 h-10 bg-green-100 text-green-600 rounded-full flex items-center justify-center border-2 border-white shadow-sm overflow-hidden">
                <img src={`https://i.pravatar.cc/150?u=${currentUser.id}`} alt="User" />
              </button>
              <div className="absolute right-0 mt-2 w-48 bg-white border rounded-xl shadow-xl hidden group-hover:block overflow-hidden animate-fade-in z-50">
                <div className="p-4 border-b bg-gray-50">
                  <p className="text-sm font-bold text-gray-800 truncate">{currentUser.name}</p>
                  <p className="text-[10px] text-gray-400 truncate">{currentUser.email}</p>
                </div>
                <button 
                  onClick={() => setActiveTab('profile')} 
                  className="w-full text-left px-4 py-3 text-sm hover:bg-gray-50 flex items-center gap-2"
                >
                  <User size={16} /> My Profile
                </button>
                <button 
                  onClick={() => setActiveTab('settings')} 
                  className="w-full text-left px-4 py-3 text-sm hover:bg-gray-50 flex items-center gap-2"
                >
                  <Settings size={16} /> Farm Settings
                </button>
                <button 
                  onClick={handleLogout} 
                  className="w-full text-left px-4 py-3 text-sm hover:bg-red-50 text-red-600 flex items-center gap-2 border-t"
                >
                  <LogOut size={16} /> Log Out
                </button>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8">
        {/* Sub Header / Welcome */}
        <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-3xl font-black text-gray-800">
              Welcome back, {currentUser.name.split(' ')[0]}
            </h2>
            <div className="flex items-center gap-2 mt-1">
              <p className="text-gray-500 font-medium text-sm">Viewing data for:</p>
              <div className="flex items-center gap-1.5 px-2.5 py-1 bg-green-100 text-green-700 rounded-full text-xs font-bold">
