            </div>
            <div>
              <p className="text-xl font-black text-slate-900">12k Tonnes</p>
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Residue Saved</p>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );

  const renderContent = () => {
    switch (activeTab) {
      case 'crop': return <CropAdvisor language={lang} initialLocation={activeLocation} />;
      case 'rates': return <MarketDashboard />;
      case 'waste': 
      case 'carbon': return <SustainablePortal />;
      case 'market': return <Marketplace />;
      case 'climate': return <ClimateAlerts location={activeLocation} />;
      case 'guide': return <PlantingGuide language={lang} />;
      default: return <LandingPage />;
    }
  };

  if (isAuthChecking) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-emerald-50">
        <Sprout className="w-12 h-12 text-emerald-600 animate-bounce" />
      </div>
    );
  }

  if (!currentUser) {
    return <Auth onLoginSuccess={(user) => {
      setCurrentUser(user);
      setActiveLocation(user.location);
    }} />;
  }

  return (
    <div className={`min-h-screen flex flex-col ${accessMode === AccessibilityMode.HIGH_CONTRAST ? 'bg-black text-white' : 'bg-white'}`}>
      {/* Navbar */}
      <header className="bg-white/95 backdrop-blur-2xl border-b sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-10">
            <div 
              className="flex items-center gap-3 cursor-pointer group" 
              onClick={() => setActiveTab('home')}
            >
              <div className="bg-emerald-950 p-2.5 rounded-xl text-white shadow-xl group-hover:scale-110 transition-transform">
                <Zap size={18} fill="currentColor" />
              </div>
              <h1 className="text-2xl font-black text-emerald-950 font-bebas tracking-[0.1em]">AgriSage</h1>
            </div>

            <nav className="hidden lg:flex items-center gap-8">
              {['Market', 'Crop', 'Rates', 'Climate'].map((item) => (
                <button 
                  key={item}
                  onClick={() => setActiveTab(item.toLowerCase())}
                  className={`text-[10px] font-black uppercase tracking-[0.2em] transition-all relative group ${activeTab === item.toLowerCase() ? 'text-emerald-600' : 'text-slate-400 hover:text-emerald-950'}`}
                >
                  {item}
                  <span className={`absolute -bottom-1 left-0 h-0.5 bg-emerald-600 transition-all ${activeTab === item.toLowerCase() ? 'w-full' : 'w-0 group-hover:w-full'}`}></span>
                </button>
              ))}
            </nav>
          </div>

          <div className="flex items-center gap-4">
            {/* Global Location Picker */}
            <div className="relative group hidden sm:block">
              <button className="flex items-center gap-3 px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl hover:bg-white transition-all text-slate-700 shadow-sm">
                <MapPin className="w-4 h-4 text-emerald-600" />
                <span className="text-[10px] font-black uppercase tracking-widest max-w-[120px] truncate">{activeLocation}</span>
                <ChevronDown className="w-3 h-3 opacity-40" />
              </button>
              <div className="absolute right-0 mt-3 w-56 bg-white border border-slate-100 rounded-2xl shadow-2xl hidden group-hover:block overflow-hidden animate-fade-in z-50">
                <div className="max-h-80 overflow-y-auto p-2 space-y-1">
                  {LOCATIONS.map(loc => (
                    <button 
                      key={loc} 
                      onClick={() => setActiveLocation(loc)}
                      className={`w-full text-left px-4 py-3 text-[9px] font-black uppercase rounded-xl hover:bg-emerald-50 transition flex items-center gap-3 ${activeLocation === loc ? 'text-emerald-800 bg-emerald-50' : 'text-slate-500'}`}
                    >
                      <MapPin className="w-3 h-3" />
                      {loc}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="h-6 w-px bg-slate-200 mx-2 hidden md:block"></div>

            {/* Language Picker */}
            <div className="relative group">
              <button className="flex items-center gap-2 px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl hover:bg-white transition-all shadow-sm">
                <Globe className="w-4 h-4 text-slate-400" />
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-700">{lang}</span>
              </button>
              <div className="absolute right-0 mt-3 w-32 bg-white border border-slate-100 rounded-2xl shadow-2xl hidden group-hover:block overflow-hidden animate-fade-in z-50">
                {LANGUAGES.map(l => (
                  <button 
                    key={l.code} 
                    onClick={() => setLang(l.code)}
                    className={`w-full text-left px-4 py-3 text-[9px] font-black uppercase hover:bg-emerald-50 transition ${lang === l.code ? 'text-emerald-950' : 'text-slate-500'}`}
                  >
                    {l.name}
                  </button>
                ))}
              </div>
            </div>

            <button 
              onClick={toggleAccess}
              className={`p-2.5 rounded-xl transition-all border shadow-sm ${accessMode !== AccessibilityMode.NORMAL ? 'bg-lime-400 text-emerald-950 border-lime-500' : 'bg-slate-50 text-slate-400 hover:bg-white border-slate-100'}`}
            >
              <Accessibility size={18} />
            </button>

            {/* User Profile */}
            <div className="relative group">
              <button className="w-10 h-10 bg-emerald-100 rounded-xl flex items-center justify-center border-2 border-white shadow-xl overflow-hidden transition-transform active:scale-90">
                <img src={`https://i.pravatar.cc/150?u=${currentUser.id}`} alt="User" className="w-full h-full object-cover" />
              </button>
              <div className="absolute right-0 mt-3 w-56 bg-white border border-slate-100 rounded-2xl shadow-2xl hidden group-hover:block overflow-hidden animate-fade-in z-50">
                <div className="p-4 border-b bg-slate-50">
                  <p className="text-[11px] font-black text-emerald-950 truncate">{currentUser.name}</p>
                </div>
                <button onClick={() => setActiveTab('profile')} className="w-full text-left px-4 py-4 text-[10px] font-black uppercase tracking-widest text-slate-600 hover:bg-emerald-50 flex items-center gap-3">
                  <User size={14} /> Profile
                </button>
                <button onClick={handleLogout} className="w-full text-left px-4 py-4 text-[10px] font-black uppercase tracking-widest text-red-600 hover:bg-red-50 flex items-center gap-3 border-t">
                  <LogOut size={14} /> Log Out
                </button>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 w-full bg-slate-50/50">
        {activeTab !== 'home' && (
          <div className="max-w-7xl mx-auto px-6 my-12">
             <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-10 border-b-4 border-emerald-950">
                <div className="space-y-2">
                  <nav className="flex items-center gap-2.5 text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">
                    <span className="cursor-pointer hover:text-emerald-600" onClick={() => setActiveTab('home')}>Home</span>
                    <ChevronRight size={10} strokeWidth={3} />
                    <span className="text-emerald-600">{activeTab}</span>
                  </nav>
                  <h2 className="text-4xl md:text-5xl font-black text-emerald-950 tracking-tighter uppercase leading-none">
                    {activeTab === 'crop' && 'Crop Advisory Engine'}
                    {activeTab === 'market' && 'Seed & Agri Marketplace'}
                    {activeTab === 'rates' && 'Market Intelligence'}
                    {activeTab === 'climate' && 'Precision Forecast'}
                    {activeTab === 'guide' && 'Agricultural Library'}
                    {activeTab === 'waste' && 'Waste Exchange'}
                  </h2>
                </div>
                <div className="flex items-center gap-4 bg-emerald-950 p-4 rounded-2xl text-white shadow-2xl">
                   <div className="p-3 bg-lime-400 rounded-xl text-emerald-950"><CloudSun size={24} /></div>
                   <div className="space-y-0.5">
                     <p className="text-[8px] font-black text-emerald-400 uppercase tracking-[0.3em]">{activeLocation}</p>
                     <p className="text-2xl font-black leading-none tracking-tight">28°C <span className="text-[10px] font-bold text-white/50 ml-1 uppercase">Partly Sunny</span></p>
                   </div>
                </div>
             </div>
          </div>
        )}

        <div className="max-w-7xl mx-auto px-6">
          {renderContent()}
        </div>
      </main>

      {/* Compact FAB Ask AI */}
      <button 
        onClick={() => setShowAi(true)}
        className="fixed bottom-8 right-8 p-4 bg-emerald-950 text-white rounded-2xl shadow-2xl hover:scale-110 active:scale-90 transition-all z-40 flex items-center gap-3 group border border-white/10 ring-4 ring-white/50 backdrop-blur-md"
      >
        <div className="relative bg-lime-400 p-2 rounded-lg text-emerald-950 shadow-lg">
          <Zap size={18} fill="currentColor" />
        </div>
        <span className="font-black tracking-widest uppercase text-[11px] pr-2">Ask AI Advisor</span>
      </button>

      {showAi && <VoiceChat language={lang} onClose={() => setShowAi(false)} />}
    </div>
  );
};

export default App;
